/* Binary search dispatcher */
BlockFunc find_block(u32 pc) {
    int lo = 0, hi = NUM_BLOCKS - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (block_table[mid].addr == pc) return block_table[mid].func;
        if (block_table[mid].addr < pc) lo = mid + 1;
        else hi = mid - 1;
    }
    return NULL; /* fallback to interpreter */
}
